    if (r < 0 || r >= n || c < 0 || c >= n || grid[r][c] == 0 || visited[r][c]) return false;
    visited[r][c] = true;
    if (solve(grid, visited, r + 1, c, n) || solve(grid, visited, r, c + 1, n)) return true;
    visited[r][c] = false;
