    }
}

fun ratInMaze(arr: IntArray): Int {
    val n = arr[0]
    val grid = Array(n) { IntArray(n) }
    var idx = 1
    for (i in 0 until n) for (j in 0 until n) { grid[i][j] = arr[idx]; idx++ }
    if (grid[0][0] == 0 || grid[n-1][n-1] == 0) return 0
    val visited = Array(n) { BooleanArray(n) }

    fun solve(r: Int, c: Int): Boolean {
        if (r == n - 1 && c == n - 1) return true
        if (r < 0 || r >= n || c < 0 || c >= n || grid[r][c] == 0 || visited[r][c]) return false
        visited[r][c] = true
        if (solve(r + 1, c) || solve(r, c + 1)) return true
        visited[r][c] = false
        return false
    }

    return if (solve(0, 0)) 1 else 0
}

def rat_in_maze(arr: list[int]) -> int:
    n = arr[0]
    grid = [[0] * n for _ in range(n)]
    idx = 1
    for i in range(n):
        for j in range(n):
            grid[i][j] = arr[idx]
            idx += 1

    if grid[0][0] == 0 or grid[n - 1][n - 1] == 0:
        return 0

    visited = [[False] * n for _ in range(n)]

    def solve(r: int, c: int) -> bool:
        if r == n - 1 and c == n - 1:
            return True
        if r < 0 or r >= n or c < 0 or c >= n:
            return False
        if grid[r][c] == 0 or visited[r][c]:
            return False
        visited[r][c] = True
        if solve(r + 1, c) or solve(r, c + 1):
            return True
        visited[r][c] = False
        return False

    return 1 if solve(0, 0) else 0

pub fn rat_in_maze(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let mut grid = vec![vec![0i32; n]; n];
    let mut idx = 1;
    for i in 0..n {
        for j in 0..n {
            grid[i][j] = arr[idx]; idx += 1;
        }
    }
    if grid[0][0] == 0 || grid[n-1][n-1] == 0 { return 0; }
    let mut visited = vec![vec![false; n]; n];

    fn solve(grid: &Vec<Vec<i32>>, visited: &mut Vec<Vec<bool>>, r: i32, c: i32, n: i32) -> bool {
        if r == n - 1 && c == n - 1 { return true; }
        if r < 0 || r >= n || c < 0 || c >= n { return false; }
        let (ru, cu) = (r as usize, c as usize);
        if grid[ru][cu] == 0 || visited[ru][cu] { return false; }
        visited[ru][cu] = true;
        if solve(grid, visited, r + 1, c, n) || solve(grid, visited, r, c + 1, n) { return true; }
        visited[ru][cu] = false;
        false
    }

    if solve(&grid, &mut visited, 0, 0, n as i32) { 1 } else { 0 }
}

